#include<iostream>#include<vector>#include<cmath>#include<algorithm>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll>a(n);        ll total_sum=0;        for( int i=0;i<n;i++){            cin>>a[i];            total_sum+=a[i];        }                ll ans=0;        ll sum=0;        for(int i=0;i<n-1;i++){            sum += a[i];            ans= max(ans, __gcd(total_sum - sum, sum));        }        cout<<ans<<"\n";    } }